func getGuildInitials(name string) string {
	if len(name) == 0 {
		return "??"
	}
	if len(name) == 1 {
		return name[0:1]
	}
	// Get first two letters or first letter of first two words
	words := []rune(name)
	if len(words) >= 2 {
		return string(words[0:2])
	}
	return string(words[0:1])
}

func getGuildColor(id string) string {
	colors := []string{
		"bg-discord-accent",
		"bg-purple-600",
		"bg-orange-500",
		"bg-pink-500",
		"bg-teal-500",
		"bg-blue-500",
		"bg-green-500",
		"bg-red-500",
	}
	hash := 0
	for _, c := range id {
		hash += int(c)
	}
	return colors[hash%len(colors)]
}

func formatTimeAgo(t time.Time) string {
	elapsed := time.Since(t)
	if elapsed < time.Minute {
		return "just now"
	} else if elapsed < time.Hour {
		mins := int(elapsed.Minutes())
		if mins == 1 {
			return "1 min ago"
		}
		return fmt.Sprintf("%d min ago", mins)
	} else if elapsed < 24*time.Hour {
		hours := int(elapsed.Hours())
		if hours == 1 {
			return "1 hour ago"
		}
		return fmt.Sprintf("%d hours ago", hours)
	} else {
		days := int(elapsed.Hours() / 24)
		if days == 1 {
			return "1 day ago"
		}
		return fmt.Sprintf("%d days ago", days)
	}
}

func getSyncStatusText(updatedAt time.Time) string {
	elapsed := time.Since(updatedAt)
	if elapsed < 10*time.Minute {
		return "Active"
	}
	return "Synced"
}

func getSyncStatusColor(updatedAt time.Time) string {
	elapsed := time.Since(updatedAt)
	if elapsed < 10*time.Minute {
		return "text-green-400"
	}
	return "text-discord-muted"
}

